Entirely untested. `systemDark` is computed at module load from `window.matchMedia`, making the module hard to test in isolation — same "no seam" issue as above.

- Gaps:
  - `bumpFontScale`: clamping at `1.3` max and `0.85` min — untested boundaries, plus rounding to 2 decimal places (`0.001` delta accumulation).
  - `resolveReaderTheme`: `readerTheme: null` → derives from `appTheme`; `readerTheme` explicitly set → overrides. Untested for both branches.
  - `updatePrefs`: partial patch merge — untested.
```ts
describe('bumpFontScale', () => {
  it('clamps at the upper bound of 1.3', () => {
    updatePrefs({ fontScale: 1.29 })
    bumpFontScale(0.5)
    expect(usePrefsSnapshot().fontScale).toBe(1.3)
  })
  it('clamps at the lower bound of 0.85', () => {
    updatePrefs({ fontScale: 0.86 })
    bumpFontScale(-0.5)
    expect(usePrefsSnapshot().fontScale).toBe(0.85)
  })
  it('rounds to 2 decimal places', () => {
    updatePrefs({ fontScale: 1 })
    bumpFontScale(0.001)
    expect(usePrefsSnapshot().fontScale).toBe(1) // rounds away tiny deltas
  })
})

describe('resolveReaderTheme', () => {
  it('falls back to dark when appTheme is dark and readerTheme is null', () => {
    expect(resolveReaderTheme({ appTheme: 'dark', readerTheme: null, fontScale: 1, wide: false })).toBe('dark')
  })
  it('falls back to paper when appTheme is light and readerTheme is null', () => {
    expect(resolveReaderTheme({ appTheme: 'light', readerTheme: null, fontScale: 1, wide: false })).toBe('paper')
  })
  it('prefers an explicit readerTheme over appTheme', () => {
    expect(resolveReaderTheme({ appTheme: 'light', readerTheme: 'dark', fontScale: 1, wide: false })).toBe('dark')
  })
})
```

